 * @param arr the input vector
 * @returns a sorted copy of the vector
 */
std::vector<int> heap_sort(std::vector<int> arr) {
    int n = static_cast<int>(arr.size());

    // Build max heap
    for (int i = n / 2 - 1; i >= 0; i--) {
