pub fn heap_sort(arr: &[i32]) -> Vec<i32> {
    let mut result = arr.to_vec();
    let n = result.len();

    if n <= 1 {
        return result;
    }

    // Build max heap
    for i in (0..n / 2).rev() {
        heapify(&mut result, n, i);
    }

    // Extract elements
    for i in (1..n).rev() {
        result.swap(0, i);
        heapify(&mut result, i, 0);
    }

    result
}

